const express = require("express");
const mysql = require("mysql2");
const path = require("path");
const bodyParser = require("body-parser");

const app = express();
const PORT = 3000;

// Middleware
app.use(bodyParser.json());
app.use(express.static(path.join(__dirname, "public"))); // folder public untuk HTML

// ===== MySQL Connection =====
const db = mysql.createPool({
  host: "localhost",
  user: "root",      // ganti sesuai MySQL kamu
  password: "",
  database: "db_absensi"
});

// ===== API Endpoints =====

// Ambil absensi terbaru
app.get("/api/absensi", (req, res) => {
  const limit = parseInt(req.query.limit) || 10;
  const sql = `
    SELECT a.*, u.nama, u.departemen
    FROM absensi a
    LEFT JOIN users u ON a.id_kartu = u.id_kartu
    ORDER BY a.created_at_jkt DESC
    LIMIT ?
  `;
  db.query(sql, [limit], (err, results) => {
    if (err) return res.status(500).json({ error: err.message });
    res.json(results);
  });
});

// Statistik
app.get("/api/stats", (req, res) => {
  const stats = {};
  const queries = [
    `SELECT COUNT(*) AS total_data FROM absensi`,
    `SELECT COUNT(*) AS today_data FROM absensi WHERE tanggal = CURDATE()`,
    `SELECT COUNT(DISTINCT id_kartu) AS unique_cards FROM absensi`,
    `SELECT COUNT(DISTINCT mac) AS unique_devices FROM absensi`
  ];

  db.query(queries[0], (err, result) => { stats.total_data = result[0].total_data;
    db.query(queries[1], (err, result) => { stats.today_data = result[0].today_data;
      db.query(queries[2], (err, result) => { stats.unique_cards = result[0].unique_cards;
        db.query(queries[3], (err, result) => { stats.unique_devices = result[0].unique_devices;
          res.json(stats);
        });
      });
    });
  });
});

// Simulasi tap kartu (POST)
app.post("/api/tap", (req, res) => {
  const { id_kartu, mac } = req.body;
  if (!id_kartu) return res.status(400).json({ success: false, message: "ID kartu wajib diisi" });

  // Cari user
  db.query("SELECT * FROM users WHERE id_kartu = ?", [id_kartu], (err, users) => {
    if (err) return res.status(500).json({ success: false, message: err.message });

    const user = users[0];
    const tanggal = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
    const jam = new Date().toTimeString().slice(0, 8);

    db.query(
      "INSERT INTO absensi (user_id, id_kartu, mac, jam, tanggal) VALUES (?, ?, ?, ?, ?)",
      [user ? user.id : null, id_kartu, mac || "Unknown", jam, tanggal],
      (err, result) => {
        if (err) return res.status(500).json({ success: false, message: err.message });
        res.json({ success: true, message: "Tap berhasil", data: { user_id: user?.id, nama: user?.nama, departemen: user?.departemen, id_kartu, jam, tanggal } });
      }
    );
  });
});

// Serve dashboard
app.get("/dashboard.html", (req, res) => {
  res.sendFile(path.join(__dirname, "public/data.html"));
});

app.listen(PORT, () => console.log(`Server berjalan di http://localhost:${PORT}`));
